func (a *adapter) SetFlag(ctx context.Context, input appcustominvoicing.SetFlagInput) error {
	if err := input.Validate(); err != nil {
		return err
	}
	return entutils.TransactingRepoWithNoValue(ctx, a, func(ctx context.Context, tx *adapter) error {
		return tx.db.AppCustomInvoicing.Update().
			Where(appcustominvoicing.ID(input.ID), appcustominvoicing.Namespace(input.Namespace), appcustominvoicing.DeletedAtIsNil()).
			SetFlag(input.Value).
			Exec(ctx)
	})
}

type (
	GetInvoiceStatusRequest  = appcustominvoicing.GetInvoiceStatusInput
	GetInvoiceStatusResponse = api.Invoice
	GetInvoiceStatusParams   = struct{ InvoiceID string `json:"invoiceId"` }
	GetInvoiceStatusHandler  httptransport.HandlerWithArgs[GetInvoiceStatusRequest, GetInvoiceStatusResponse, GetInvoiceStatusParams]
)

func (h *handler) GetInvoiceStatus() GetInvoiceStatusHandler {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, params GetInvoiceStatusParams) (GetInvoiceStatusRequest, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil { return GetInvoiceStatusRequest{}, fmt.Errorf("failed to resolve namespace: %w", err) }
			return GetInvoiceStatusRequest{InvoiceID: billing.InvoiceID{ID: params.InvoiceID, Namespace: ns}}, nil
		},
		func(ctx context.Context, request GetInvoiceStatusRequest) (GetInvoiceStatusResponse, error) {
			if err := request.Validate(); err != nil { return GetInvoiceStatusResponse{}, err }
			invoice, err := h.service.GetInvoiceStatus(ctx, request)
			if err != nil { return GetInvoiceStatusResponse{}, err }
			return billinghttpdriver.MapStandardInvoiceToAPI(invoice)
		},
		commonhttp.JSONResponseEncoderWithStatus[GetInvoiceStatusResponse](http.StatusOK),
		httptransport.AppendOptions(h.options,
			httptransport.WithOperationName("GetInvoiceStatus"),
			httptransport.WithErrorEncoder(errorEncoder()))...,
	)
}

func (s *Service) VoidInvoice(ctx context.Context, input appcustominvoicing.VoidInvoiceInput) (billing.StandardInvoice, error) {
	if err := input.Validate(); err != nil {
		return billing.StandardInvoice{}, err
	}
	return transaction.Run(ctx, s.adapter, func(ctx context.Context) (billing.StandardInvoice, error) {
		invoice, err := s.billingService.GetStandardInvoiceById(ctx, billing.GetStandardInvoiceByIdInput{Invoice: input.InvoiceID})
		if err != nil { return billing.StandardInvoice{}, err }
		if err := s.ValidateInvoiceApp(invoice); err != nil { return billing.StandardInvoice{}, err }
		err = s.billingService.TriggerInvoice(ctx, billing.InvoiceTriggerServiceInput{
			InvoiceTriggerInput: billing.InvoiceTriggerInput{Invoice: input.InvoiceID, Trigger: billing.TriggerVoid},
			AppType:    app.AppTypeCustomInvoicing,
			Capability: app.CapabilityTypeCollectPayments,
		})
		if err != nil { return billing.StandardInvoice{}, err }
		invoice, err = s.billingService.GetStandardInvoiceById(ctx, billing.GetStandardInvoiceByIdInput{Invoice: input.InvoiceID})
		if err != nil { return billing.StandardInvoice{}, err }
		critical := lo.Filter(invoice.ValidationIssues, func(i billing.ValidationIssue, _ int) bool { return i.Severity == billing.ValidationIssueSeverityCritical })
		if len(critical) > 0 { return billing.StandardInvoice{}, billing.ValidationError{Err: critical.AsError()} }
		return invoice, nil
	})
}
